module.render:
    const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    const direction = args.direction === 'right' ? 'right' : 'left';
    const name = args.name || '';
    const image = args.image || '';
    const contentStr = sections[0] ? sections[0].trim() : '';

    const avatarHtml = image
      ? `<img src="${esc(image)}" class="mdp-avatar-image" alt="${esc(name)}" />`
      : `<div class="mdp-avatar-circle">${name ? esc(name.charAt(0).toUpperCase()) : 'U'}</div>`;

    let vars = '';
    if (args.bubblecolor && String(args.bubblecolor).trim()) vars += '--balloon-bg:' + String(args.bubblecolor).trim() + ';';
    if (args.avatarcolor && String(args.avatarcolor).trim()) vars += '--balloon-avatar-bg:' + String(args.avatarcolor).trim() + ';';
    if (args.textcolor && String(args.textcolor).trim()) vars += '--balloon-text:' + String(args.textcolor).trim() + ';';
    const fs = (args.fontsize && String(args.fontsize).trim()) || '1em';
    if (fs !== '1em') vars += '--balloon-fs:' + fs + ';';
    const styleAttr = vars ? ` style="${vars}"` : '';

    return `\n\n<div class="mdp-mod-balloon mdp-balloon-${direction}"${styleAttr}>
<div class="mdp-balloon-avatar">
${avatarHtml}
${name ? `<div class="mdp-avatar-name">${esc(name)}</div>` : ''}
</div>
<div class="mdp-balloon-bubble">

${contentStr}

</div>
</div>\n\n`;
